# Define allowed origins explicitly instead of using wildcard
# This prevents unauthorized domains from making cross-origin requests
ALLOWED_ORIGINS = [
    "http://localhost:3000",
    "http://localhost:5173",
    "http://localhost:8080",
    "https://staging.example.com",
    "https://app.example.com",
    "https://www.example.com",
]

ALLOWED_METHODS = ["GET", "POST", "OPTIONS"]
ALLOWED_HEADERS = ["Content-Type", "Authorization"]
MAX_AGE = "3600"
MAX_CONTENT_LENGTH = 1_048_576  # 1 MB


def get_allowed_origin(request_origin):
    """Check if the request origin is in the allowed list and return it, or None."""
    if request_origin and request_origin in ALLOWED_ORIGINS:
        return request_origin
    return None


def set_cors_headers(headers, origin):
    """Set CORS headers with a specific allowed origin (not wildcard)."""
    allowed_origin = get_allowed_origin(origin)
    if allowed_origin:
        headers["Access-Control-Allow-Origin"] = allowed_origin
    # Vary header is important when Access-Control-Allow-Origin is not *
    headers["Vary"] = "Origin"
    headers["Access-Control-Allow-Methods"] = ", ".join(ALLOWED_METHODS)
    headers["Access-Control-Allow-Headers"] = ", ".join(ALLOWED_HEADERS)
    headers["Access-Control-Max-Age"] = MAX_AGE
    # Do not allow credentials with wildcard origins
    # Only set this if we have a specific allowed origin
    if allowed_origin:
        headers["Access-Control-Allow-Credentials"] = "true"
    return headers


def set_security_headers(headers):
    """Set standard security headers."""
    headers["X-Content-Type-Options"] = "nosniff"
    headers["X-Frame-Options"] = "DENY"
    headers["X-XSS-Protection"] = "1; mode=block"
    headers["Content-Security-Policy"] = "default-src 'none'"
    headers["Strict-Transport-Security"] = "max-age=31536000; includeSubDomains"
    headers["Referrer-Policy"] = "no-referrer"
    headers["Cache-Control"] = "no-store, no-cache, must-revalidate"
    return headers


def sanitize_string(value, max_length=1000):
    """Sanitize a string input to prevent injection attacks."""
    if not isinstance(value, str):
        return None
    # Truncate to max length
    value = value[:max_length]
    # HTML-escape to prevent XSS
    value = html.escape(value, quote=True)
    return value


def validate_request_content_length(request):
    """Validate that the request body doesn't exceed the maximum allowed size."""
    content_length = request.content_length
    if content_length and content_length > MAX_CONTENT_LENGTH:
        return False
    return True


def create_response(data, status_code, request_origin):
    """Create a properly formatted response with security and CORS headers."""
    headers = {}
    headers = set_cors_headers(headers, request_origin)
    headers = set_security_headers(headers)
    headers["Content-Type"] = "application/json"

    response_body = json.dumps(data, default=str)
    return (response_body, status_code, headers)


